import { ref, onMounted } from 'vue';
export default {
  name: 'Configuration',
  setup() {
    const loading = ref(true);
    const saving = ref(false);
    const success = ref(null);
    const config = ref({
      quote_validity_hours: 24,
      rental_rate_36: 3.5,
      rental_rate_60: 2.5
    });
    const loadConfig = async () => {
      try {
        loading.value = true;

        // Chargement simulé de la configuration
        config.value = {
          quote_validity_hours: 24,
          rental_rate_36: 3.5,
          rental_rate_60: 2.5
        };
      } catch (e) {
        console.error('Error loading config:', e);
      } finally {
        loading.value = false;
      }
    };
    const saveConfig = async () => {
      try {
        saving.value = true;
        success.value = null;

        // Enregistrement simulé de la configuration
        console.log('Configuration saved:', config.value);
        success.value = 'Configuration enregistrée avec succès';
        setTimeout(() => {
          success.value = null;
        }, 3000);
      } catch (e) {
        alert('Erreur lors de l\'enregistrement: ' + e.message);
      } finally {
        saving.value = false;
      }
    };
    onMounted(() => {
      loadConfig();
    });
    return {
      loading,
      saving,
      success,
      config,
      saveConfig
    };
  }
};
